import Vue from 'vue';
import Cryptoicon from 'vue-cryptoicon';
import Toasted from 'vue-toasted';
import icon from 'vue-cryptoicon/src/icons';
import App from './App.vue';
import router from './router';

Vue.config.productionTip = false;

Cryptoicon.add(icon);
Vue.use(Cryptoicon);
Vue.use(Toasted);

new Vue({
  router,
  render: h => h(App),
}).$mount('#app');
